(309, '2026-11-07', 'Blessed Assurance', '{"reference":"Matthew 6:33","text":"Seek first his kingdom and his righteousness, and all these things will be given to you."}'::jsonb, 'Heaven is backing you today. Angels are on assignment for your protection and provision. Walk in confidence, knowing that the Creator of the universe is fighting for you.', '["Father, protect me from the schemes of the enemy","Cover me with Your precious blood","Station Your angels around me"]'::jsonb, '["I am healed by His stripes","Divine health is my portion","Sickness has no place in my body"]'::jsonb, 'Moses Afolabi'),
(310, '2026-11-08', 'Perfect Love', '{"reference":"Philippians 4:13","text":"I can do all things through Christ who strengthens me."}'::jsonb, 'Let faith arise in your heart. The same God who parted the Red Sea is able to make a way for you. Nothing is too difficult for Him. Believe and receive His miracle power.', '["Lord, heal every area of brokenness in my life","Restore what the enemy has stolen","Make me whole in Jesus'' name"]'::jsonb, '["Abundance flows to me","My needs are met according to His riches","I am a generous giver"]'::jsonb, 'Moses Afolabi'),
