(312, '2026-11-10', 'Faithful Promise', '{"reference":"Psalm 37:4","text":"Delight yourself in the Lord, and he will give you the desires of your heart."}'::jsonb, 'The Holy Spirit is your guide, comforter, and empowerer. Lean into His leading today. He will direct your paths and give you wisdom for every decision.', '["Holy Spirit, fill me afresh today","Use me as a vessel of Your love","Let Your power flow through me"]'::jsonb, '["My family is blessed","Salvation reigns in my household","Generational curses are broken"]'::jsonb, 'Moses Afolabi'),
(313, '2026-11-11', 'Endless Mercy', '{"reference":"Isaiah 40:31","text":"Those who hope in the Lord will renew their strength."}'::jsonb, 'God''s love for you is unconditional and unwavering. You cannot do anything to make Him love you more or less. Rest secure in His perfect love today.', '["Lord, fill me with Your peace that surpasses understanding","Guide my steps according to Your will","Protect me and my loved ones today"]'::jsonb, '["I am blessed and highly favored","God''s grace is upon my life","I walk in divine victory"]'::jsonb, 'Moses Afolabi'),
